frappe.listview_settings['Batch'] = {
    onload: function(listview) {
        listview.page.add_inner_button(__('Print'), function() {
            let selected_docs = listview.get_checked_items();
            if (selected_docs.length > 0) {
                let docnames = selected_docs.map(doc => doc.name);
                call_print_selected_docs(docnames);
            } else {
                frappe.msgprint(__('Please select at least one document to print.'));
            }
        });
    }
};

function call_print_selected_docs(docnames) {
    // Construct the dictionary format expected by the backend
    let doctype_dict = {
        "Sales Invoice": docnames
    };

    frappe.call({
        method: 'mhr.utilis.generate_multi_pdf_url',
        args: {
            doctype: doctype_dict,
        },
        callback: function(r) {
            console.log(r.message);
            if (r.message) {
                var pdf_url = r.message;
                var w = window.open(pdf_url);
                if (!w) {
                    frappe.msgprint(__('Please enable pop-ups'));
                    return;
                }
            }
        }
    });
}

