frappe.ui.form.on('Delivery Note', {
    refresh: function(frm) {
        // Only calculate if document is draft
        if (frm.doc.docstatus === 0) {
            calculate_total_cone(frm);
        }
    }
});

frappe.ui.form.on('Delivery Note Item', {
    items_add: function(frm, cdt, cdn) {
        if (frm.doc.docstatus === 0) {
            calculate_total_cone(frm);
        }
    },
    items_remove: function(frm, cdt, cdn) {
        if (frm.doc.docstatus === 0) {
            calculate_total_cone(frm);
        }
    },
    custom_cone: function(frm, cdt, cdn) {
        if (frm.doc.docstatus === 0) {
            calculate_total_cone(frm);
        }
    }
});

// Function to calculate total cone safely
function calculate_total_cone(frm) {
    let total_cone = 0;

    (frm.doc.items || []).forEach(function(row) {
        total_cone += parseFloat(row.custom_cone || 0);
    });

    // Round to 2 decimals to avoid floating point issues
    total_cone = parseFloat(total_cone.toFixed(2));

    // Only update if value really changed
    if (parseFloat(frm.doc.custom_total_cone || 0) !== total_cone) {
        frm.set_value('custom_total_cone', total_cone);
        // No need to call refresh_field, set_value handles it
    }
}

frappe.listview_settings['Delivery Note'] = frappe.listview_settings['Delivery Note'] || {};

frappe.listview_settings['Delivery Note'] = {
  ...frappe.listview_settings['Delivery Note'],
  onload: function (listview) {
    // Add custom button to the list view
    listview.page.add_action_item(__('Send Email'), function () {
      const selected_docs = listview.get_checked_items();

      if (selected_docs.length === 0) {
        frappe.msgprint(__('Please select at least one Delivery Note'));
        return;
      }

      // Use the first document to fetch full data
      const first_doc = selected_docs[0].name;
      const all_docs = selected_docs.map(doc => doc.name);

      frappe.call({
        method: "frappe.client.get",
        args: {
          doctype: "Delivery Note",
          name: first_doc
        },
        callback: function (r) {
          if (!r.exc) {
            const doc = r.message;

            // Get default print format
            const print_format = frappe.get_meta("Delivery Note").default_print_format || "Standard";

            // Prepare attachments for all selected delivery notes
            const attachments = all_docs.map(dn_name => ({
              print_format: print_format,
              doctype: "Delivery Note",
              name: dn_name
            }));

            // Generate subject line
            let subject = "";
            if (all_docs.length === 1) {
              subject = `Delivery Note: ${all_docs[0]}`;
            } else {
              subject = `Delivery Notes: ${all_docs[0]} and ${all_docs.length - 1} more`;
            }

            // Open the standard email dialog
            new frappe.views.CommunicationComposer({
              doc: doc,
              subject: subject,
              recipients: doc.contact_email || "",
              attach_document_print: false, // We'll handle attachments manually
              attachments: ["http://localhost:89/files/1386.pdf"],
              sender: frappe.user.name,
              sender_full_name: frappe.user.full_name,
              frm: null // Since we're in list view
            });
          }
        }
      });
    });
  }
};

// Store the original settings before modification
const originalListViewSettings =
	frappe.listview_settings["Delivery Note"] || {};

// Create a new object with the original settings
frappe.listview_settings["Delivery Note"] = {
	...originalListViewSettings,

	// Override onload while preserving the original functionality
	onload: function (listview) {
		// Call the original onload function if it exists
		if (originalListViewSettings.onload) {
			originalListViewSettings.onload(listview);
		}

		// Add custom button for creating delivery trip
		listview.page.add_action_item(
			__("Create Delivery Trip"),
			function () {
				const selected_docs = listview.get_checked_items();

				if (selected_docs.length === 0) {
					frappe.msgprint(
						__("Please select at least one Delivery Note")
					);
					return;
				}

				// Get the names of all selected delivery notes
				const delivery_note_names = selected_docs.map(
					(doc) => doc.name
				);

				// Fetch complete details of all selected delivery notes
				frappe.call({
					method: "frappe.client.get_list",
					args: {
						doctype: "Delivery Note",
						fields: [
							"name",
							"customer",
							"customer_address",
							"contact_person",
							"shipping_address_name",
							"company",
							"grand_total",
						],
						filters: {
							name: ["in", delivery_note_names],
						},
					},
					callback: function (r) {
						if (r.exc) {
							frappe.msgprint(
								__("Error fetching delivery notes")
							);
							return;
						}

						if (!r.message || !r.message.length) {
							frappe.msgprint(
								__("No valid Delivery Notes found")
							);
							return;
						}

						const delivery_notes = r.message;
						const companies = new Set(
							delivery_notes.map((dn) => dn.company)
						);

						// Validate that all delivery notes belong to the same company
						if (companies.size > 1) {
							frappe.msgprint(
								__(
									"Selected Delivery Notes must belong to the same company"
								)
							);
							return;
						}

						// Create a new delivery trip
						frappe.model.with_doctype(
							"Delivery Trip",
							function () {
								const delivery_trip =
									frappe.model.get_new_doc(
										"Delivery Trip"
									);

								// Set basic delivery trip details
								delivery_trip.company =
									delivery_notes[0].company;
								delivery_trip.departure_time =
									frappe.datetime.now_datetime();

								// Add delivery stops for each delivery note
								delivery_notes.forEach(function (dn) {
									const child =
										frappe.model.add_child(
											delivery_trip,
											"Delivery Stop",
											"delivery_stops"
										);

									child.delivery_note = dn.name;
									child.customer = dn.customer;
									child.address =
										dn.shipping_address_name ||
										dn.customer_address;
									child.contact = dn.contact_person;
									child.grand_total = dn.grand_total;
									child.estimated_arrival =
										frappe.datetime.now_datetime();
								});

								// Open the new delivery trip form
								frappe.set_route(
									"Form",
									"Delivery Trip",
									delivery_trip.name
								);
							}
						);
					},
				});
			}
		);

		// Add custom button for sending email (preserve the existing functionality)

	},
};

