frappe.ui.form.on('Delivery Stop', {
    custom_total_cones: function(frm, cdt, cdn) {
        calculate_totals_and_save_if_empty(frm);
    },
    custom_total_quantity: function(frm, cdt, cdn) {
        calculate_totals_and_save_if_empty(frm);
    },
    custom_item_length: function(frm, cdt, cdn) {
        calculate_totals_and_save_if_empty(frm);
    },
    delivery_stops_remove: function(frm) {
        calculate_totals_and_save_if_empty(frm);
    }
});

function calculate_totals_and_save_if_empty(frm) {
    const is_cones_empty = !flt(frm.doc.custom_total_cones);
    const is_qty_empty = !flt(frm.doc.custom_total_quantity);

    // Only proceed if at least one total field is empty
    if (!(is_cones_empty || is_qty_empty || is_length_empty)) {
        return;
    }

    let total_cones = 0;
    let total_qty = 0;
    let total_length = 0;

    (frm.doc.delivery_stops || []).forEach(function(row) {
        total_cones += flt(row.custom_total_cones);
        total_qty += flt(row.custom_total_quantity);
        total_length += flt(row.custom_item_length);
    });

    let updated = false;

    if (is_cones_empty) {
        frm.set_value('custom_total_cones', total_cones);
        updated = true;
    }

    if (is_qty_empty) {
        frm.set_value('custom_total_quantity', total_qty);
        updated = true;
    }

    if (is_length_empty) {
        // frm.set_value('custom_total_item_length', total_length);
        updated = true;
    }

    if (updated) {
        frappe.after_ajax(() => {
            frm.save();
        });
    }
}

