function set_next_challan_no(frm) {

    const allowed_series = [
        "SMP-DN-.YYYY.-",
        "MAT-DN-.YYYY.-",
        "MAT-DN-RET-.YYYY.-"
    ];

    if (!allowed_series.includes(frm.doc.naming_series)) {
        return;
    }

    frappe.db.get_list("Delivery Note", {
        fields: ["challan_number"],
        filters: {
            naming_series: frm.doc.naming_series,
            docstatus: 1
        },
        order_by: "creation desc",
        limit: 1
    }).then(records => {

        let next_no = 1;   // ✅ default

        if (records.length && records[0].challan_number) {
            next_no = parseInt(records[0].challan_number) + 1;
        }

        // ✅ ✅ ✅ ALWAYS SET AS STRING (VERY IMPORTANT)
        frm.set_value("challan_number", String(next_no));
    });
}

