    onload_post_render(frm) {
        bind_cone_handlers(frm);
    },

    refresh(frm) {
        bind_cone_handlers(frm);
    },

    before_save(frm) {
        let promises = [];

        (frm.doc.items || []).forEach(row => {
            // Ensure cone copy exists
            if (
                (!row.custom_cone_copy || row.custom_cone_copy === "") &&
                row.custom_cone
            ) {
                row.custom_cone_copy = row.custom_cone;
            }

            // Skip if qty manually edited
            if (row.custom_qty_manual_edit) return;

            if (row.batch_no && row.custom_cone && row.custom_cone_copy) {
                promises.push(
                    fetch_batch_qty_and_calculate(row.name, row)
                );
            }
        });

        if (promises.length > 0) {
            frappe.validated = false;

            Promise.all(promises).then(() => {
                frappe.validated = true;
            });
        }
    }
});

function bind_cone_handlers(frm) {
    let grid = frm.fields_dict["items"].grid;

    // Unbind previous handlers to prevent duplicates
    grid.wrapper.off("focus", "input[data-fieldname='custom_cone']");
    grid.wrapper.off("change", "input[data-fieldname='custom_cone']");
    grid.wrapper.off("change", "input[data-fieldname='qty']");

    /* ------------------------------------------------------------
       1) Capture previous cone value BEFORE edit (on focus)
    ------------------------------------------------------------ */
    grid.wrapper.on(
        "focus",
        "input[data-fieldname='custom_cone']",
        function () {
            let $input = $(this);
            let cdn = $input.closest(".grid-row").attr("data-name");
            let row = locals["Delivery Note Item"][cdn];

            if (!row) return;

            let currentVal = $input.val();

            // Save original cone value only once
            if (
                (!row.custom_cone_copy || row.custom_cone_copy === "") &&
                currentVal !== undefined &&
                currentVal !== ""
            ) {
                frappe.model.set_value(
                    "Delivery Note Item",
                    cdn,
                    "custom_cone_copy",
                    parseFloat(currentVal)
                );
            }

            $input.data("prev-cone", currentVal);
        }
    );

    /* ------------------------------------------------------------
       2) Handle cone change → recalc qty from DB
    ------------------------------------------------------------ */
    grid.wrapper.on(
        "change",
        "input[data-fieldname='custom_cone']",
        function () {
            let $input = $(this);
            let cdn = $input.closest(".grid-row").attr("data-name");
            let row = locals["Delivery Note Item"][cdn];

            if (!row) return;

            // Restore cone_copy if empty
            if (
                (!row.custom_cone_copy || row.custom_cone_copy === "") &&
                $input.data("prev-cone") !== undefined
            ) {
                let prev = $input.data("prev-cone");
                if (prev !== "" && prev !== undefined) {
                    frappe.model.set_value(
                        "Delivery Note Item",
                        cdn,
                        "custom_cone_copy",
                        parseFloat(prev)
                    );
                }
            }

            // Reset manual qty edit flag
            frappe.model.set_value(
                "Delivery Note Item",
                cdn,
                "custom_qty_manual_edit",
                0
            );

            calculate_qty_from_database(cdn, row);
        }
    );

    /* ------------------------------------------------------------
       3) Track manual qty edits (PERSISTED FIELD)
    ------------------------------------------------------------ */
    grid.wrapper.on(
        "change",
        "input[data-fieldname='qty']",
        function () {
            let $input = $(this);
            let cdn = $input.closest(".grid-row").attr("data-name");
            let row = locals["Delivery Note Item"][cdn];

            if (!row) return;

            frappe.model.set_value(
                "Delivery Note Item",
                cdn,
                "custom_qty_manual_edit",
                1
            );
        }
    );
}

