                        frm.doc.items = (frm.doc.items || []).filter(row => row.item_code);
                        batches.forEach(function(data) {
                            let exists = frm.doc.items.some(row => row.batch_no === data.name);
                            if (!exists) {
                                frm.add_child('items', {
                                    item_code: data.item,
                                    qty: data.batch_qty,
                                    conversion_factor: 1,
                                    transfer_qty: flt(data.batch_qty),
                                    batch_no: data.name,
                                    uom: data.stock_uom,
                                    custom_cone: data.custom_cone,
                                    use_serial_batch_fields: 1
                                });
                                if (data.custom_notes && !frm.doc.custom_notes) {
                                    frm.set_value('custom_notes', data.custom_notes);
                                }
                            }
                        });
                        frm.refresh_field('items');
                        calculate_totals(frm);
                    } else {
                        frappe.msgprint(__('No batches found matching the criteria.'));
                    }
                    frm.set_value('custom_fetch_batches', 0);
                }
            });
        });
    }
});

frappe.ui.form.on('Stock Entry Detail', {
    items_add: function(frm) { calculate_totals(frm); },
    items_remove: function(frm) { calculate_totals(frm); },
    qty: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        let cf = row.conversion_factor || 1;
        frappe.model.set_value(cdt, cdn, 'transfer_qty', flt(row.qty) * flt(cf));
        calculate_totals(frm);
    },
    conversion_factor: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        frappe.model.set_value(cdt, cdn, 'transfer_qty', flt(row.qty) * flt(row.conversion_factor || 1));
    },
    custom_cone: function(frm) { calculate_totals(frm); }
});

function calculate_totals(frm) {
    let total_cone = 0;
    let total_qty = 0;
    (frm.doc.items || []).forEach(function(row) {
        total_cone += parseFloat(row.custom_cone || 0);
        total_qty += parseFloat(row.qty || 0);
    });
    if (frm.doc.custom_total_cone !== total_cone) {
        frm.doc.custom_total_cone = total_cone;
        frm.refresh_field('custom_total_cone');
    }
    if (String(frm.doc.custom_total_qty) !== String(total_qty)) {
        frm.doc.custom_total_qty = String(total_qty);
        frm.refresh_field('custom_total_qty');
    }
}

function get_container_no(frm, callback) {
    if (!frm.doc.custom_container_number) { callback(null); return; }
    frappe.db.get_value('Container', frm.doc.custom_container_number, 'container_no', function(r) {
        callback(r && r.container_no ? r.container_no : frm.doc.custom_container_number);
    });
}

function fetch_and_append_batch_se(frm) {
    if (!frm.doc.custom_supplier_batch_no || !frm.doc.custom_container_number || !frm.doc.custom_lot_no) return;
    get_container_no(frm, function(container_no) {
        frappe.call({
            method: 'mhr.utilis.get_delivery_note_batch',
            args: {
                lot_no: frm.doc.custom_lot_no,
                container_no: container_no,
                supplier_batch_no: frm.doc.custom_supplier_batch_no,
                glue: frm.doc.custom_glue,
                pulp: frm.doc.custom_pulp,
                fsc: frm.doc.custom_fsc,
                lusture: frm.doc.custom_lusture,
                grade: frm.doc.custom_grade,
                cone: frm.doc.custom_se_cone,
                denier: frm.doc.custom_denier
            },
            callback: function(response) {
                if (!response.message) return;
                let data = response.message;
                let exists = frm.doc.items.some(row => row.batch_no === data.batch_no);
                if (exists) {
                    frappe.msgprint(__('Batch already exists in the list.'));
                    return;
                }
                frm.add_child('items', {
                    item_code: data.item_code,
                    qty: data.qty,
                    conversion_factor: 1,
                    transfer_qty: flt(data.qty),
                    batch_no: data.batch_no,
                    uom: data.uom,
                    custom_cone: data.cone,
                    use_serial_batch_fields: 1
                });
                frm.doc.items.unshift(frm.doc.items.pop());
                frm.refresh_field('items');
                frm.set_value('custom_supplier_batch_no', '');
                if (data.notes) {
                    frm.set_value('custom_notes', data.notes);
                }
                calculate_totals(frm);
            }
        });
    });
}

function clear_batch_fields_se(frm) {
    ['custom_glue', 'custom_pulp', 'custom_lusture', 'custom_grade', 'custom_lot_no', 'custom_fsc', 'custom_denier', 'custom_se_cone'].forEach(field => frm.set_value(field, ''));
}
